import{_ as a,o as e,c as s,ag as l}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"App 组合根","description":"","frontmatter":{},"headers":[],"relativePath":"app.md","filePath":"app.md","lastUpdated":1775459233000}'),p={name:"app.md"};function t(d,i,o,n,r,h){return e(),s("div",null,[...i[0]||(i[0]=[l(`<h1 id="app-组合根" tabindex="-1">App 组合根 <a class="header-anchor" href="#app-组合根" aria-label="Permalink to &quot;App 组合根&quot;">​</a></h1><p>App 层是 ModLink Studio 的最终桌面宿主入口。<br> 它的职责不是重新定义 SDK 契约，也不是接管 Core 的运行时细节，而是把已经存在的几层能力装配成一个真正可启动的应用。</p><p>如果概括成一句话，可以理解为：</p><ul><li>SDK 定义 driver 契约</li><li>Core 托管 driver、流和录制相关运行时</li><li>UI 提供页面和窗口</li><li>App 负责把这些东西组装成最终程序</li></ul><h2 id="这页主要回答什么" tabindex="-1">这页主要回答什么 <a class="header-anchor" href="#这页主要回答什么" aria-label="Permalink to &quot;这页主要回答什么&quot;">​</a></h2><p>这页主要回答四个问题：</p><ol><li>最终用户从哪里启动宿主</li><li>App 层启动时到底会创建哪些对象</li><li>已安装的 driver 是怎么被发现的</li><li>App 层保留了哪些 fail-fast 边界</li></ol><h2 id="启动入口" tabindex="-1">启动入口 <a class="header-anchor" href="#启动入口" aria-label="Permalink to &quot;启动入口&quot;">​</a></h2><p>正式安装方式见 <a href="/install">安装与发布</a>。安装完成后，App 层提供两个入口：</p><p>正式用户入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-studio</span></span></code></pre></div><p>调试入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink_studio</span></span></code></pre></div><p>这两个入口最终都会走到同一个启动逻辑，本质上都会调用同一套 <code>main()</code>。<br> 对实际使用来说，这里最重要的区别只有一件事：是否带控制台输出。</p><ul><li><code>modlink-studio</code> 作为 GUI 入口，日常使用时通常不会额外带一个控制台窗口</li><li><code>python -m modlink_studio</code> 是从终端直接启动，标准输出和报错都会留在当前控制台里</li></ul><p>因此当前建议是：</p><ul><li>日常启动宿主：<code>modlink-studio</code></li><li>联调 driver、看日志和排查报错：<code>python -m modlink_studio</code></li></ul><h2 id="app-层到底负责什么" tabindex="-1">App 层到底负责什么 <a class="header-anchor" href="#app-层到底负责什么" aria-label="Permalink to &quot;App 层到底负责什么&quot;">​</a></h2><p>App 层是组合根。它对系统做的事情很具体：</p><ol><li>创建或复用 <code>QApplication</code></li><li>设置应用名、图标和主题</li><li>初始化设置服务</li><li>发现当前环境里的 driver factories</li><li>创建 <code>ModLinkEngine</code></li><li>创建主窗口 <code>MainWindow</code></li><li>启动 Qt 事件循环</li></ol><p>这层的核心特征是“装配”，而不是“定义新协议”。<br> 也就是说，App 层负责把现成的 SDK、Core、UI 和插件接起来，而不是在这里定义设备协议、流模型或录制格式。</p><h2 id="一个启动流程大概长什么样" tabindex="-1">一个启动流程大概长什么样 <a class="header-anchor" href="#一个启动流程大概长什么样" aria-label="Permalink to &quot;一个启动流程大概长什么样&quot;">​</a></h2><p>从当前实现看，宿主启动顺序大致是：</p><ol><li>创建 <code>QApplication</code></li><li>加载应用图标和主题</li><li>创建 <code>SettingsService</code></li><li>扫描 <code>modlink.drivers</code></li><li>用扫描到的 driver factories 创建 <code>ModLinkEngine</code></li><li>用这个 engine 创建 <code>MainWindow</code></li><li><code>show()</code> 窗口并进入 Qt 事件循环</li></ol><p>这条顺序有助于理解 App 层和其他层之间的关系：</p><ul><li>driver 发现发生在应用启动阶段</li><li>Core 运行时在窗口创建前就已经准备好</li><li>UI 页面拿到的是已经组装好的 engine，而不是自己去拼 driver 或流总线</li></ul><h2 id="插件发现模型" tabindex="-1">插件发现模型 <a class="header-anchor" href="#插件发现模型" aria-label="Permalink to &quot;插件发现模型&quot;">​</a></h2><p>宿主不会在运行时临时下载插件，也不会要求最终用户拼接本地路径。当前模型是“先安装，再发现”：</p><ul><li>官方插件通过 <code>modlink-studio[...]</code> extras 安装</li><li>外部 driver 用普通 <code>pip install</code> 或 <code>pip install -e</code> 安装到同一个 Python 环境</li><li>宿主启动时扫描当前环境里的 <code>modlink.drivers</code></li></ul><p>例如一个外部 driver 的典型联调方式是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../my_driver</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink_studio</span></span></code></pre></div><p>这个模型意味着两件事：</p><ul><li>App 层只负责发现已经安装好的 driver</li><li>driver 的安装和版本管理发生在 Python 包环境层，而不是宿主界面层</li></ul><h2 id="为什么外部-driver-不依赖宿主应用" tabindex="-1">为什么外部 driver 不依赖宿主应用 <a class="header-anchor" href="#为什么外部-driver-不依赖宿主应用" aria-label="Permalink to &quot;为什么外部 driver 不依赖宿主应用&quot;">​</a></h2><p><code>modlink-studio</code> 是最终桌面宿主，不是 driver 的最小公共接口。</p><p>外部 driver 更合理的依赖边界是：</p><ul><li>默认依赖 <code>modlink-sdk</code></li><li>只有确实需要运行时服务时，才额外依赖 <code>modlink-core</code></li></ul><p>这样做的原因不是“形式上分层”，而是为了让 driver 依赖最小稳定接口，而不是反向绑死在整个宿主应用上。<br> App 层只负责在启动时把这些已安装 driver 发现出来，并把它们交给 Core 和 UI 使用。</p><h2 id="app-层保留的-fail-fast-边界" tabindex="-1">App 层保留的 fail-fast 边界 <a class="header-anchor" href="#app-层保留的-fail-fast-边界" aria-label="Permalink to &quot;App 层保留的 fail-fast 边界&quot;">​</a></h2><p>App 层当前明确保留 fail-fast 策略。</p><p>这意味着：</p><ul><li>损坏的 driver entry point 会在启动或加载阶段直接暴露错误</li><li>未知 payload 类型不会在 App 层被静默吞掉</li><li>明显的插件协议错误应尽早暴露，而不是拖到运行过程中变成更难排查的问题</li></ul><p>这里的判断很明确：driver 是系统核心组成，不是可有可无的附属插件。<br> 如果 driver 协议本身有问题，让宿主尽早失败，通常比启动一个语义不清的应用更合理。</p><h2 id="仓库内联调" tabindex="-1">仓库内联调 <a class="header-anchor" href="#仓库内联调" aria-label="Permalink to &quot;仓库内联调&quot;">​</a></h2><p><code>plugins/</code> 目录里保留的是官方插件源目录和开发态示例插件。<br> 在 monorepo 根目录联调时，可以通过根项目 extras 启动宿主：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --extra</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> official-host-camera</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --extra</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> official-openbci-ganglion</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio</span></span></code></pre></div><p>如果目的是理解 driver 契约，优先继续看 <a href="/sdk">SDK</a>。<br> 如果目的是理解 runtime 如何托管 driver 和流，继续看 <a href="/core">Core</a>。</p>`,48)])])}const u=a(p,[["render",t]]);export{k as __pageData,u as default};
